import openpyxlimport pathlib"""Домашняя библиотека"""class RatingError(Exception):    """Raised when rating is not in [0;10]"""    class LibraryError(Exception):    """Raised when there is problem with adding book"""    class Book:    """Репрезентация книи в библиотеке"""    def __init__(self, title, author, form="", genre="", rating=0, year=0, country = ""):        Book.CheckingRating(rating)        self.title = title        self.author = author        self.form = form        self.genre = genre        self.rating = rating        self.year = year        self.country = country    def __str__(self):        return (f"Title - {self.title}, author - {self.author}, form - {self.form}, "         f"ganre - {self.genre}, rating - {self.rating}, year - {self.year}")    def rating_update(self, rating):        Book.CheckingRating(rating)        self.rating = rating    def ganre_update(self, genre):        self.genre = genre    def year_update(self, year):        self.year = year    def CheckingRating(rating):        if not isinstance(rating, (int, float)) or (rating>10 or rating<0):            raise RatingError("Rating must be number range from 0 to 10")  class Library:    lib_path = pathlib.Path.home() / "Desktop/home_library"    num_of_info = 6    def __init__(self, name):        self.name = name        pathlib.Path(Library.lib_path).mkdir(exist_ok=True)        if (Library.lib_path / f"{name}.xlsx").is_file():            pass        else:            library = openpyxl.Workbook()            types = ["title", "author", "form", "genre", "rating", "year"]            ws = library.active            for i in range (1, Library.num_of_info+1):                ws.cell(1, i).value = types[i-1]            library.save(Library.lib_path / f"{self.name}.xlsx")    def book_add(self, book):        wb, ws = Library.openlibrary(self)        for i in range(1, ws.max_row+1):            if book.title == ws.cell(i, 1).value:                book_title = book.title                book_author = ws.cell(i, 2).value                book_elements = [ws.cell(i, k).value for k in range(3, Library.num_of_info+1)]                book_args = [ws.cell(1, k).value for k in range(3, Library.num_of_info+1)]                other = dict(zip(book_args, book_elements))                BookDupli = Library.create_book_obj(book_title, book_author, **other)                raise LibraryError(f"Книга с таким названием уже есть в библиотеке: {str(BookDupli)}")        book_row = ws.max_row+1        for i in range(1, Library.num_of_info+1):            ws.cell(book_row, i).value = list(vars(book).values())[i-1]        wb.save(Library.lib_path / f"{self.name}.xlsx")    def filter_books(self, **kwargs):         wb, ws = Library.openlibrary(self)        elements_of_search = list(kwargs.keys())        values_to_search = list(kwargs.values())        rows_needed = []        books = []        for i in range(1, Library.num_of_info+1):            if ws.cell(1, i).value in elements_of_search:                rows_needed.append(i)        for i in range (1, ws.max_row+1):            summa = 0            counter = 0            for elem in rows_needed:                if ws.cell(i, elem).value == values_to_search[counter]:                    summa += 1                counter += 1            if summa == len(elements_of_search):                book_title = ws.cell(i, 1).value                book_author = ws.cell(i, 2).value                book_elements = [ws.cell(i, k).value for k in range(3, Library.num_of_info+1)]                book_args = [ws.cell(1, k).value for k in range(3, Library.num_of_info+1)]                other = dict(zip(book_args, book_elements))                BookFetched = Library.create_book_obj(book_title, book_author, **other)                books.append(BookFetched)        if len(books) == 0:            print("Не удалось найти книги, удовлетворяющие запросу")        else:            print("Вот книги, удовлетворяющие запросу:")            for book in books:                print(book)        wb.save(Library.lib_path / f"{self.name}.xlsx")    def openlibrary(self):        wb = openpyxl.load_workbook(Library.lib_path / f"{self.name}.xlsx")        ws = wb.active        return wb, ws    def create_book_obj(title, author, **kwargs):        return Book(title, author, **kwargs)            Book1 = Book("Ужасные ужасы", "Иванов", "рассказ", "ужасы", 10)Book2 = Book("Фантастическая фантастика", "Орлов", "",  "фантастика", 8, 2004)Book3 = Book("Любовная любовь", "Кириешков", "повесть", "любовное", 10, 2007)Book4 = Book("Новые ужасы", "Варварова", "антология", "ужасы", 10)Book5 = Book("Новейшие ужасы", "Варварова", "антология", "ужасы", 8)lib1 = Library("Библиотека")search = {"genre": "любовное"}lib1.filter_books(**search)